     7→namespace APIs_BeFirst.Service.AOI
     8→{
     9→    /// <summary>
    10→    /// Service implementation for AOI (Automated Optical Inspection) data operations
    11→    /// </summary>
    12→    public class AOIService : IAOIService
    13→    {
    14→        private readonly IConfiguration _configuration;
    15→        private readonly string _connectionString;
    16→
    17→        public AOIService(IConfiguration configuration)
    18→        {
    19→            _configuration = configuration;
    20→            // Assuming MES database connection (where Machines_Extractor_AOI tables reside)
    21→            _connectionString = _configuration.GetConnectionString("MES")
    22→                ?? throw new InvalidOperationException("MES connection string not found");
    23→        }
    24→
    25→        /// <summary>
    26→        /// Submit a single AOI inspection record
    27→        /// </summary>
    28→        public async Task<AOIDataResponse> SubmitInspectionAsync(AOIDataRequest request)
    29→        {
    30→            var response = new AOIDataResponse();
    31→
    32→            try
    33→            {
    34→                using (var connection = new SqlConnection(_connectionString))
    35→                {
    36→                    await connection.OpenAsync();
    37→
    38→                    // Insert main AOI data record
    39→                    var insertQuery = @"
    40→                        INSERT INTO Machines_Extractor_AOI_Data
    41→                        (
    42→                            AOIID,
    43→                            StationID,
    44→                            PartNumber,
    45→                            PartID,
    46→                            Side,
    47→                            SerialNumber,
    48→                            Position,
    49→                            Result,
    50→                            Operator,
    51→                            InspectionDate,
    52→                            DefectCodeID,
    53→                            CreatedDate
    54→                        )
    55→                        VALUES
    56→                        (
    57→                            @AOIID,
    58→                            @StationID,
    59→                            @PartNumber,
    60→                            @PartID,
    61→                            @Side,
    62→                            @SerialNumber,
    63→                            @Position,
    64→                            @Result,
    65→                            @Operator,
    66→                            @InspectionDate,
    67→                            @DefectCodeID,
    68→                            GETDATE()
    69→                        );
    70→                        SELECT SCOPE_IDENTITY();";
    71→
    72→                    using (var command = new SqlCommand(insertQuery, connection))
    73→                    {
    74→                        command.Parameters.AddWithValue("@AOIID", request.AOIID);
    75→                        command.Parameters.AddWithValue("@StationID", request.StationID);
    76→                        command.Parameters.AddWithValue("@PartNumber", request.PartNumber);
    77→                        command.Parameters.AddWithValue("@PartID", request.PartID);
    78→                        command.Parameters.AddWithValue("@Side", request.Side);
    79→                        command.Parameters.AddWithValue("@SerialNumber", request.SerialNumber);
    80→                        command.Parameters.AddWithValue("@Position", request.Position);
    81→                        command.Parameters.AddWithValue("@Result", request.Result);
    82→                        command.Parameters.AddWithValue("@Operator", (object?)request.Operator ?? DBNull.Value);
    83→                        command.Parameters.AddWithValue("@InspectionDate", request.InspectionDate ?? DateTime.Now);
    84→                        command.Parameters.AddWithValue("@DefectCodeID", (object?)request.DefectCodeID ?? DBNull.Value);
    85→
    86→                        var mainRecordId = await command.ExecuteScalarAsync();
    87→                        int recordsInserted = 1;
    88→
    89→                        // Insert defect details if any
    90→                        if (request.Defects != null && request.Defects.Any())
    91→                        {
    92→                            foreach (var defect in request.Defects)
    93→                            {
    94→                                var defectQuery = @"
    95→                                    INSERT INTO Machines_Extractor_AOI_Data_Details
    96→                                    (
    97→                                        AOIDataID,
    98→                                        Position,
    99→                                        Location,
   100→                                        PinNumber,
   101→                                        X,
   102→                                        Y,
   103→                                        DefectCode,
   104→                                        UserResult
   105→                                    )
   106→                                    VALUES
   107→                                    (
   108→                                        @AOIDataID,
   109→                                        @Position,
   110→                                        @Location,
   111→                                        @PinNumber,
   112→                                        @X,
   113→                                        @Y,
   114→                                        @DefectCode,
   115→                                        @UserResult
   116→                                    )";
   117→
   118→                                using (var defectCommand = new SqlCommand(defectQuery, connection))
   119→                                {
   120→                                    defectCommand.Parameters.AddWithValue("@AOIDataID", mainRecordId);
   121→                                    defectCommand.Parameters.AddWithValue("@Position", request.Position);
   122→                                    defectCommand.Parameters.AddWithValue("@Location", (object?)defect.Location ?? DBNull.Value);
   123→                                    defectCommand.Parameters.AddWithValue("@PinNumber", (object?)defect.PinNumber ?? DBNull.Value);
   124→                                    defectCommand.Parameters.AddWithValue("@X", (object?)defect.X ?? DBNull.Value);
   125→                                    defectCommand.Parameters.AddWithValue("@Y", (object?)defect.Y ?? DBNull.Value);
   126→                                    defectCommand.Parameters.AddWithValue("@DefectCode", (object?)defect.DefectCode ?? DBNull.Value);
   127→                                    defectCommand.Parameters.AddWithValue("@UserResult", (object?)defect.UserResult ?? DBNull.Value);
   128→
   129→                                    await defectCommand.ExecuteNonQueryAsync();
   130→                                    recordsInserted++;
   131→                                }
   132→                            }
   133→                        }
   134→
   135→                        response.Success = true;
   136→                        response.Message = "AOI inspection data submitted successfully";
   137→                        response.RecordsInserted = recordsInserted;
   138→                    }
   139→                }
   140→            }
   141→            catch (Exception ex)
   142→            {
   143→                response.Success = false;
