   150→        /// <summary>
   151→        /// Submit multiple AOI inspection records in batch
   152→        /// </summary>
   153→        public async Task<AOIBatchResponse> SubmitInspectionBatchAsync(List<AOIDataRequest> requests)
   154→        {
   155→            var response = new AOIBatchResponse
   156→            {
   157→                TotalRecords = requests.Count,
   158→                SuccessfulRecords = 0,
   159→                FailedRecords = 0
   160→            };
   161→
   162→            foreach (var request in requests)
   163→            {
   164→                try
   165→                {
   166→                    var result = await SubmitInspectionAsync(request);
   167→                    if (result.Success)
   168→                    {
   169→                        response.SuccessfulRecords++;
   170→                    }
   171→                    else
   172→                    {
   173→                        response.FailedRecords++;
   174→                        response.Errors?.Add($"SN {request.SerialNumber}: {result.Message}");
   175→                    }
   176→                }
   177→                catch (Exception ex)
   178→                {
   179→                    response.FailedRecords++;
   180→                    response.Errors?.Add($"SN {request.SerialNumber}: {ex.Message}");
   181→                }
   182→            }
   183→
   184→            response.Success = response.FailedRecords == 0;
   185→            return response;
   186→        }
