```csharp
public class SettingsService : ModelBase, ISettingsService
{
    protected readonly ProdMesDbContext _context;

    public SettingsService(ProdMesDbContext context) : base(context)
    {
        _context = context;
    }

    public async Task<List<SettingsResponse>> GetSettings()
    {
        var dtDetails = await _context.Settings
            .AsQueryable()
            .Select(x => new SettingsResponse
            {
                Setting_Name = x.Description,
                Setting_Value = x.Result
            })
            .ToListAsync();
        return dtDetails;
    }
}
```

**Pattern**:
- Interface defines async Task-based contract
- Implementation inherits from ModelBase
- Constructor receives DbContext and passes to base
- Stores context as protected field for subclass access
- Uses Entity Framework async queries (`.ToListAsync()`, `.FirstOrDefaultAsync()`)
- Returns typed response objects

