### 9. **AOI Controller Pattern**

**Location**: `S:\01_Repos\BeFirst_APIs\BeFirst_APIs\Controllers\AOIController.cs`

```csharp
[ApiController]
[Route("[controller]")]
public class AOIController : ControllerBase
{
    private readonly IAOIService _aoiService;
    private readonly ILogger<AOIController> _logger;

    public AOIController(IAOIService aoiService, ILogger<AOIController> logger)
    {
        _aoiService = aoiService;
        _logger = logger;
    }

    [Authorize]
    [HttpPost("SubmitInspection")]
    [ProducesResponseType(typeof(AOIDataResponse), StatusCodes.Status200OK)]
    [ProducesResponseType(StatusCodes.Status400BadRequest)]
    [ProducesResponseType(StatusCodes.Status401Unauthorized)]
    [ProducesResponseType(StatusCodes.Status500InternalServerError)]
    public async Task<ActionResult<AOIDataResponse>> SubmitInspection([FromBody] AOIDataRequest request)
    {
        try
        {
            _logger.LogInformation($"AOI data submission received: AOIID={request.AOIID}");

            if (!ModelState.IsValid)
            {
                return BadRequest(ModelState);
            }

            var result = await _aoiService.SubmitInspectionAsync(request);

            if (result.Success)
            {
                _logger.LogInformation($"AOI data submitted successfully: {result.RecordsInserted} records");
                return Ok(result);
            }
            else
            {
                _logger.LogWarning($"AOI data submission failed: {result.Message}");
                return BadRequest(result);
            }
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "Error in SubmitInspection endpoint");
            return StatusCode(500, new AOIDataResponse
            {
                Success = false,
                Message = $"Internal server error: {ex.Message}"
            });
        }
    }
}
```

**Pattern**:
- Uses ProducesResponseType attributes for Swagger documentation
- Receives ILogger<T> for structured logging
- Validates ModelState before processing
- Comprehensive exception handling
- Logs at different levels (Information, Warning, Error)

